## 추가할 함수
- fetchMedications(): Promise<MedicationAPI[]>
- createMedication(input: CreateMedicationInput): Promise<MedicationAPI>
- updateMedication(id: string, input: Partial<CreateMedicationInput>): Promise<MedicationAPI>
- deleteMedication(id: string): Promise<void>
- fetchMedicationLogs(params: { date?: string; startDate?: string; endDate?: string }): Promise<MedicationLogAPI[]>
- toggleMedicationLog(medicationId: string, scheduleId: string, date: string): Promise<MedicationLogAPI>

